    linkPracticalsToTopics() {
        Object.entries(this.mathematicsExperiments).forEach(([expId, experiment]) => {
            experiment.relatedTopics.forEach(topicId => {
                if (this.mathematicsTopics[topicId]) {
                    if (!this.mathematicsTopics[topicId].relatedExperiments) {
                        this.mathematicsTopics[topicId].relatedExperiments = [];
                    }
                    this.mathematicsTopics[topicId].relatedExperiments.push({
                        id: expId,
                        name: experiment.name,
                        category: experiment.category
                    });
                }
            });
        });
    }
    


