            // ─────────────────────────────────────────────
            // 7. TRIGONOMETRIC IDENTITIES
            // ─────────────────────────────────────────────
            trigonometricIdentities: {
                overview: "Equations involving trigonometric functions that hold for all valid values of the variable",

                pythagoreanIdentities: {
                    primary: "sin²θ + cos²θ = 1",
                    derivedForms: [
                        "sin²θ = 1 − cos²θ",
                        "cos²θ = 1 − sin²θ"
                    ],
                    secondForm: "1 + tan²θ = sec²θ  (divide primary by cos²θ)",
                    thirdForm: "1 + cot²θ = csc²θ  (divide primary by sin²θ)",
                    derivation: "From x² + y² = 1 on the unit circle, substituting x=cosθ, y=sinθ"
                },

                quotientIdentities: {
                    identities: [
                        "tan θ = sin θ / cos θ",
                        "cot θ = cos θ / sin θ"
                    ]
                },

                coFunctionIdentities: {
                    identities: [
                        "sin(90°−θ) = cos θ",
                        "cos(90°−θ) = sin θ",
                        "tan(90°−θ) = cot θ",
                        "csc(90°−θ) = sec θ",
                        "sec(90°−θ) = csc θ",
                        "cot(90°−θ) = tan θ"
                    ]
                },

                evenOddIdentities: {
                    odd: ["sin(−θ) = −sin θ", "tan(−θ) = −tan θ", "csc(−θ) = −csc θ", "cot(−θ) = −cot θ"],
                    even: ["cos(−θ) = cos θ", "sec(−θ) = sec θ"]
                },

                compoundAngleIdentities: {
                    sinAddition: "sin(A+B) = sin A cos B + cos A sin B",
                    sinSubtraction: "sin(A−B) = sin A cos B − cos A sin B",
                    cosAddition: "cos(A+B) = cos A cos B − sin A sin B",
                    cosSubtraction: "cos(A−B) = cos A cos B + sin A sin B",
                    tanAddition: "tan(A+B) = (tan A + tan B)/(1 − tan A tan B)",
                    tanSubtraction: "tan(A−B) = (tan A − tan B)/(1 + tan A tan B)",
                    examples: [
                        "sin 75° = sin(45°+30°) = (√2/2)(√3/2) + (√2/2)(1/2) = (√6+√2)/4",
                        "cos 15° = cos(45°−30°) = (√2/2)(√3/2) + (√2/2)(1/2) = (√6+√2)/4"
                    ]
                },

                doubleAngleIdentities: {
                    sin2A: "sin 2A = 2 sin A cos A",
                    cos2A: [
                        "cos 2A = cos²A − sin²A",
                        "cos 2A = 2cos²A − 1",
                        "cos 2A = 1 − 2sin²A"
                    ],
                    tan2A: "tan 2A = 2 tan A / (1 − tan²A)",
                    examples: [
                        "sin 2(30°) = 2(1/2)(√3/2) = √3/2 = sin 60° ✓",
                        "cos 2(45°) = cos²45°−sin²45° = ½−½ = 0 = cos 90° ✓"
                    ]
                },

                halfAngleIdentities: {
                    sinHalf: "sin(A/2) = ±√((1−cos A)/2)",
                    cosHalf: "cos(A/2) = ±√((1+cos A)/2)",
                    tanHalf: "tan(A/2) = ±√((1−cos A)/(1+cos A)) = sin A/(1+cos A) = (1−cos A)/sin A",
                    note: "Sign chosen based on quadrant of A/2"
                },

                provingIdentities: {
                    strategy: [
                        "Work on one side only (usually the more complex side)",
                        "Convert everything to sin and cos if stuck",
                        "Look to apply Pythagorean identities to simplify",
                        "Factorise or expand where helpful",
                        "Never 'move' terms across the equals sign — that assumes the result"
                    ],
                    example: {
                        prove: "sin²θ/(1−cos θ) = 1 + cos θ",
                        steps: [
                            "LHS = sin²θ/(1−cos θ)",
                            "= (1−cos²θ)/(1−cos θ)  [Pythagorean identity]",
                            "= (1−cos θ)(1+cos θ)/(1−cos θ)  [factorise]",
                            "= 1 + cos θ = RHS  ✓"
                        ]
                    }
                }
            },

